previewCss:
@keyframes darma-loader-darma-custom-671-blinkCursor {
  50% {
    border-right-color: transparent;
  }
}

@keyframes darma-loader-darma-custom-671-typeAndDelete {
  0%,
  10% {
    width: 0;
  }
  45%,
  55% {
    width: 6.2em;
  } /* adjust width based on content */
  90%,
  100% {
    width: 0;
  }
}

.darma-loader-darma-custom-671__terminal-loader {--loader-secondary-color: var(--loader-secondary-color, #10b981);
  --loader-bg: var(--loader-bg, #111827);

  border: 0.1em solid #333;
  background-color: var(--loader-color, #22c55e);
  color: #0f0;
  font-family: "Courier New", Courier, monospace;
  font-size: 1em;
  padding: 1.5em 1em;
  width: 12em;
  box-shadow: 0 4px 8px color-mix(in srgb, var(--loader-color, #22c55e) 45%, transparent);
  border-radius: 4px;
  position: relative;
  overflow: hidden;
  box-sizing: border-box;
}

.darma-loader-darma-custom-671__terminal-header {
  position: absolute;
  top: 0;
  left: 0;
  right: 0;
  height: 1.5em;
  background-color: #333;
  border-top-left-radius: 4px;
  border-top-right-radius: 4px;
  padding: 0 0.4em;
  box-sizing: border-box;
}

.darma-loader-darma-custom-671__terminal-controls {
  float: right;
}

.darma-loader-darma-custom-671__control {
  display: inline-block;
  width: 0.6em;
  height: 0.6em;
  margin-left: 0.4em;
  border-radius: 50%;
  background-color: #777;
}

.darma-loader-darma-custom-671__control.darma-loader-darma-custom-671__close {
  background-color: #e33;
}

.darma-loader-darma-custom-671__control.darma-loader-darma-custom-671__minimize {
  background-color: #ee0;
}

.darma-loader-darma-custom-671__control.darma-loader-darma-custom-671__maximize {
  background-color: #0b0;
}

.darma-loader-darma-custom-671__terminal-title {
  float: left;
  line-height: 1.5em;
  color: #eee;
}

.darma-loader-darma-custom-671__text {
  display: inline-block;
  white-space: nowrap;
  overflow: hidden;
  border-right: 0.2em solid green; /* Cursor */
  animation:
    darma-loader-darma-custom-671-typeAndDelete 4s steps(11) infinite,
    darma-loader-darma-custom-671-blinkCursor 0.5s step-end infinite alternate;
  margin-top: 1.5em;
}

